import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { apiClient, authService } from "@/App";
import { toast } from "sonner";
import { Building2, Upload, Image as ImageIcon } from "lucide-react";

const SchoolProfilePage = () => {
  const [loading, setLoading] = useState(true);
  const [editing, setEditing] = useState(false);
  const [logoPreview, setLogoPreview] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    address: "",
    phone: "",
    email: "",
    school_type: "",
    logo_url: "",
    motto: "",
    vision: "",
    mission: "",
    principal_name: "",
    website: "",
    established_year: ""
  });

  const user = authService.getUser();

  useEffect(() => {
    fetchSchoolProfile();
  }, []);

  const fetchSchoolProfile = async () => {
    try {
      if (user?.school_id) {
        const res = await apiClient.get(`/schools/${user.school_id}`);
        setFormData(res.data);
        if (res.data.logo_url) setLogoPreview(res.data.logo_url);
      }
    } catch (e) {
      toast.error("Failed to load profile");
    } finally {
      setLoading(false);
    }
  };

  const handleLogoUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      setLogoPreview(reader.result);
      setFormData({ ...formData, logo_url: reader.result });
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = async (e) => {
  e.preventDefault();

  try {
    if (!user?.school_id) {
      const payload = {
        ...formData,
        admin_name: user?.full_name || "Admin",
        admin_email: user?.email,
        admin_password: "12345678",
        admin_phone: user?.phone || ""
      };

      const res = await apiClient.post("/register-school", payload);
      toast.success("School created successfully");

      // 🔥 NEW ONBOARDING FLOW CONTROL
      const onboarding = res.data.onboarding;

      if (onboarding?.step === 2) {
        window.location.href =
          `/onboarding/complete-profile?school=${res.data.school_id}`;
      } else {
        window.location.href = `/s/${res.data.school_slug}`;
      }

      return;
    }

    const clean = Object.fromEntries(
      Object.entries(formData).filter(([_, v]) => v !== "")
    );

    await apiClient.patch(`/schools/${user.school_id}`, clean);

    toast.success("Profile updated");
    setEditing(false);
    fetchSchoolProfile();

 } catch (e) {
  console.error("FULL ERROR:", e);

  toast.error(
    e?.response?.data?.detail ||
    e?.response?.data?.message ||
    "Operation failed"
  );
}
};

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin w-10 h-10 border-4 border-primary border-t-transparent rounded-full" />
      </div>
    );
  }

  return (
    <div className="space-y-6">

      {/* HEADER */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold">School Profile</h1>
          <p className="text-gray-500">Manage your institution</p>
        </div>

        {!editing ? (
          <Button onClick={() => setEditing(true)}>Edit Profile</Button>
        ) : (
          <Button variant="outline" onClick={() => setEditing(false)}>
            Cancel
          </Button>
        )}
      </div>

      {/* ================= VIEW MODE ================= */}
      {!editing && (
        <div className="space-y-6">

          {/* HERO CARD */}
          <Card className="border-2 border-primary/20">
            <CardContent className="p-10 text-center space-y-6">

              {logoPreview ? (
                <img src={logoPreview} className="w-32 h-32 mx-auto rounded-xl object-contain" />
              ) : (
                <Building2 className="w-20 h-20 mx-auto text-primary" />
              )}

              <h1 className="text-4xl font-bold">{formData.name || "School Name"}</h1>
              <p className="italic text-gray-500">"{formData.motto}"</p>

              <span className="px-4 py-1 bg-primary/10 text-primary rounded-full text-sm capitalize">
                {formData.school_type || "Institution"}
              </span>

            </CardContent>
          </Card>

          {/* CONTACT GRID */}
          <div className="grid md:grid-cols-3 gap-4">

            <Card>
              <CardContent className="p-4">
                <p className="text-sm text-gray-500">Address</p>
                <p className="font-medium">{formData.address || "Not set"}</p>
              </CardContent>
            </Card>

            <Card>
              <CardContent className="p-4">
                <p className="text-sm text-gray-500">Phone</p>
                <p className="font-medium">{formData.phone || "Not set"}</p>
              </CardContent>
            </Card>

            <Card>
              <CardContent className="p-4">
                <p className="text-sm text-gray-500">Email</p>
                <p className="font-medium">{formData.email || "Not set"}</p>
              </CardContent>
            </Card>

          </div>

          {/* VISION & MISSION */}
          <div className="grid md:grid-cols-2 gap-4">

            {formData.vision && (
              <Card className="bg-blue-50">
                <CardContent className="p-5">
                  <h3 className="font-bold mb-2">Vision</h3>
                  <p>{formData.vision}</p>
                </CardContent>
              </Card>
            )}

            {formData.mission && (
              <Card className="bg-green-50">
                <CardContent className="p-5">
                  <h3 className="font-bold mb-2">Mission</h3>
                  <p>{formData.mission}</p>
                </CardContent>
              </Card>
            )}

          </div>

          {/* EXTRA INFO */}
          <Card>
            <CardContent className="p-5 grid md:grid-cols-3 gap-4">

              {formData.principal_name && (
                <div>
                  <p className="text-sm text-gray-500">Principal</p>
                  <p className="font-medium">{formData.principal_name}</p>
                </div>
              )}

              {formData.established_year && (
                <div>
                  <p className="text-sm text-gray-500">Established</p>
                  <p className="font-medium">{formData.established_year}</p>
                </div>
              )}

              {formData.website && (
                <div>
                  <p className="text-sm text-gray-500">Website</p>
                  <a className="text-blue-600" href={formData.website}>
                    Visit
                  </a>
                </div>
              )}

            </CardContent>
          </Card>

          {/* ONBOARDING */}
          {!user?.school_id && (
            <Button className="w-full" onClick={() => setEditing(true)}>
              Complete School Setup
            </Button>
          )}

        </div>
      )}

      {/* ================= EDIT MODE ================= */}
      {editing && (
        <form onSubmit={handleSubmit} className="space-y-6">

          {/* LOGO */}
          <Card>
            <CardHeader>
              <CardTitle>Logo</CardTitle>
            </CardHeader>
            <CardContent>
              <Input type="file" onChange={handleLogoUpload} />
            </CardContent>
          </Card>

          {/* BASIC */}
          <Card>
            <CardHeader>
              <CardTitle>Basic Info</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">

              <Input placeholder="School Name"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              />

              <Input placeholder="Phone"
                value={formData.phone}
                onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
              />

              <Input placeholder="Email"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
              />

              <Textarea placeholder="Address"
                value={formData.address}
                onChange={(e) => setFormData({ ...formData, address: e.target.value })}
              />

              <Input placeholder="Motto"
                value={formData.motto}
                onChange={(e) => setFormData({ ...formData, motto: e.target.value })}
              />

            </CardContent>
          </Card>

          {/* VISION & MISSION */}
          <Card>
            <CardHeader>
              <CardTitle>Vision & Mission</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">

              <Textarea placeholder="Vision"
                value={formData.vision}
                onChange={(e) => setFormData({ ...formData, vision: e.target.value })}
              />

              <Textarea placeholder="Mission"
                value={formData.mission}
                onChange={(e) => setFormData({ ...formData, mission: e.target.value })}
              />

            </CardContent>
          </Card>

          {/* EXTRA */}
          <Card>
            <CardHeader>
              <CardTitle>Additional Info</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">

              <Input placeholder="Principal"
                value={formData.principal_name}
                onChange={(e) => setFormData({ ...formData, principal_name: e.target.value })}
              />

              <Input placeholder="Established Year"
                value={formData.established_year}
                onChange={(e) => setFormData({ ...formData, established_year: e.target.value })}
              />

              <Input placeholder="Website"
                value={formData.website}
                onChange={(e) => setFormData({ ...formData, website: e.target.value })}
              />

            </CardContent>
          </Card>

          <Button type="submit" className="w-full bg-emerald-600">
            Submit & Open School Portal
          </Button>

        </form>
      )}

    </div>
  );
};

export default SchoolProfilePage;
